import { useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { CartContext } from '../context/CartContext';
import { AuthContext } from '../context/AuthContext';
import { CartItem as CartItemComponent } from '../components/CartItem';
import { Product } from '../types';

export function Cart() {
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  const { cart, updateQuantity, removeFromCart, clearCart, getCartTotal } = useContext(CartContext);

  const handleQuantityChange = (productId: number, newQuantity: number) => {
    if (newQuantity < 1) {
      removeFromCart(productId);
    } else {
      updateQuantity(productId, newQuantity);
    }
  };

  const handleRemoveItem = (productId: number) => {
    removeFromCart(productId);
  };

  const handleCheckout = () => {
    if (!user) {
      navigate('/login', { state: { from: '/checkout' } });
    } else {
      navigate('/checkout');
    }
  };

  const handleContinueShopping = () => {
    navigate('/products');
  };

  const handleClearCart = () => {
    if (window.confirm('Are you sure you want to clear your cart?')) {
      clearCart();
    }
  };

  const formatPrice = (price: number) => {
    return `$${price.toFixed(2)}`;
  };

  const cartTotal = getCartTotal();
  const itemCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  if (cart.length === 0) {
    return (
      <div className="cart-page cart-page--empty">
        <div className="cart-empty">
          <div className="cart-empty__icon">🛒</div>
          <h1 className="cart-empty__title">Your Cart is Empty</h1>
          <p className="cart-empty__message">
            Looks like you haven't added any items to your cart yet.
          </p>
          <button
            className="btn btn--primary btn--large"
            onClick={handleContinueShopping}
          >
            Start Shopping
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="cart-page">
      <div className="cart-page__header">
        <h1 className="cart-page__title">Shopping Cart</h1>
        <span className="cart-page__count">
          {itemCount} {itemCount === 1 ? 'item' : 'items'}
        </span>
      </div>

      <div className="cart-page__content">
        <div className="cart-page__items">
          <div className="cart-items">
            {cart.map((item) => (
              <CartItemComponent
                key={item.productId}
                item={item}
                onQuantityChange={handleQuantityChange}
                onRemove={handleRemoveItem}
              />
            ))}
          </div>

          <div className="cart-page__actions">
            <button
              className="btn btn--secondary"
              onClick={handleContinueShopping}
            >
              Continue Shopping
            </button>
            <button
              className="btn btn--outline"
              onClick={handleClearCart}
            >
              Clear Cart
            </button>
          </div>
        </div>

        <div className="cart-page__summary">
          <div className="cart-summary">
            <h2 className="cart-summary__title">Order Summary</h2>

            <div className="cart-summary__items">
              <div className="cart-summary__row">
                <span>Subtotal ({itemCount} items)</span>
                <span>{formatPrice(cartTotal)}</span>
              </div>
              <div className="cart-summary__row">
                <span>Shipping</span>
                <span className="cart-summary__shipping">
                  {cartTotal >= 50 ? 'FREE' : '$5.99'}
                </span>
              </div>
              <div className="cart-summary__row">
                <span>Tax (estimated)</span>
                <span>{formatPrice(cartTotal * 0.08)}</span>
              </div>
            </div>

            <div className="cart-summary__total">
              <span>Total</span>
              <span>
                {formatPrice(
                  cartTotal +
                  (cartTotal >= 50 ? 0 : 5.99) +
                  (cartTotal * 0.08)
                )}
              </span>
            </div>

            {cartTotal >= 50 && (
              <div className="cart-summary__free-shipping">
                🎉 You qualify for free shipping!
              </div>
            )}

            <button
              className="btn btn--primary btn--full btn--large"
              onClick={handleCheckout}
            >
              {user ? 'Proceed to Checkout' : 'Sign In to Checkout'}
            </button>

            {!user && (
              <p className="cart-summary__login-prompt">
                Please <a href="/login">sign in</a> to complete your order
              </p>
            )}

            <div className="cart-summary__secure">
              <span>🔒 Secure checkout</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Cart;
