      paymentInfo.cardNumber.trim() &&
      paymentInfo.expiryDate.trim() &&
      paymentInfo.cvv.trim() &&
      paymentInfo.cardholderName.trim()
    );
  };

  const handleNextStep = () => {
    setError(null);
    if (step === 1 && !validateAddress()) {
      setError('Please fill in all shipping address fields');
      return;
    }
    if (step === 2 && !validatePayment()) {
      setError('Please fill in all payment information');
      return;
    }
    setStep((prev) => Math.min(prev + 1, 3) as 1 | 2 | 3);
  };

  const handlePrevStep = () => {
    setError(null);
    setStep((prev) => Math.max(prev - 1, 1) as 1 | 2 | 3);
  };

  const handlePlaceOrder = async () => {
    if (!user) {
      setError('Please login to place an order');
      return;
    }

    setIsSubmitting(true);
    setError(null);

    try {
      const orderData = {
        userId: user.id,
        items: items.map((item: CartItem) => ({
          productId: item.productId,
          quantity: item.quantity,
          product: item.product
        })),
        total: total,
        address: address,
        paymentMethod: selectedPayment
      };

      const response = await createOrder(orderData);
      setOrderId(response.id);
      setOrderComplete(true);
      clearCart();
    } catch (err) {
      setError('Failed to place order. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const formatCardNumber = (value: string): string => {
    const v = value.replace(/\s+/g, '').replace(/[^0-9]/gi, '');
    const matches = v.match(/\d{4,16}/g);
    const match = (matches && matches[0]) || '';
    const parts = [];
    for (let i = 0, len = match.length; i < len; i += 4) {
      parts.push(match.substring(i, i + 4));
    }
    return parts.length ? parts.join(' ') : value;
  };

  const formatExpiry = (value: string): string => {
    const v = value.replace(/\s+/g, '').replace(/[^0-9]/gi, '');
    if (v.length >= 2) {
      return v.substring(0, 2) + '/' + v.substring(2, 4);
    }
    return v;
  };

  if (items.length === 0 && !orderComplete) {
