import React from 'react';
import { CartItem as CartItemType } from '../types';
import { useCart } from '../context/CartContext';
import './CartItem.css';

interface CartItemProps {
  item: CartItemType;
}

const CartItem: React.FC<CartItemProps> = ({ item }) => {
  const { updateQuantity, removeFromCart } = useCart();
  const { product, quantity, productId } = item;

  const handleIncrease = () => {
    updateQuantity(productId, quantity + 1);
  };

  const handleDecrease = () => {
    if (quantity > 1) {
      updateQuantity(productId, quantity - 1);
    } else {
      removeFromCart(productId);
    }
  };

  const handleRemove = () => {
    removeFromCart(productId);
  };

  const subtotal = product ? product.price * quantity : 0;

  return (
    <div className="cart-item">
      <div className="cart-item-image">
        {product?.image ? (
          <img src={product.image} alt={product?.name || 'Product'} />
        ) : (
          <div className="cart-item-placeholder">No Image</div>
        )}
      </div>

      <div className="cart-item-details">
        <h3 className="cart-item-name">{product?.name || 'Unknown Product'}</h3>
        <p className="cart-item-description">
          {product?.description?.substring(0, 80) || 'No description'}
          {(product?.description?.length || 0) > 80 ? '...' : ''}
        </p>
        <p className="cart-item-price">
          ${product?.price?.toFixed(2) || '0.00'}
        </p>
      </div>

      <div className="cart-item-quantity">
        <button 
          className="quantity-btn decrease" 
          onClick={handleDecrease}
          aria-label="Decrease quantity"
        >
          -
        </button>
        <span className="quantity-value">{quantity}</span>
        <button 
          className="quantity-btn increase" 
          onClick={handleIncrease}
          aria-label="Increase quantity"
        >
          +
        </button>
      </div>

      <div className="cart-item-subtotal">
        <span className="subtotal-label">Subtotal:</span>
        <span className="subtotal-value">${subtotal.toFixed(2)}</span>
      </div>

      <button 
        className="cart-item-remove" 
        onClick={handleRemove}
        aria-label="Remove item"
      >
        ×
      </button>
    </div>
  );
};

export default CartItem;
