```typescript
import express, { Application, Request, Response, NextFunction } from 'express';
import cors from 'cors';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { usersRouter } from './routes/users';
import { productsRouter } from './routes/products';
import { ordersRouter } from './routes/orders';
import { pool } from './db';

const app: Application = express();
const PORT = 3001;
const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';

// Middleware
app.use(cors());
app.use(express.json());

// Auth middleware
export interface AuthRequest extends Request {
  userId?: number;
  userRole?: string;
}

export const authMiddleware = (req: AuthRequest, res: Response, next: NextFunction): void => {
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    res.status(401).json({ error: 'No token provided' });
    return;
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as { userId: number; role: string };
    req.userId = decoded.userId;
    req.userRole = decoded.role;
    next();
  } catch {
    res.status(401).json({ error: 'Invalid token' });
  }
};

// Admin middleware
export const adminMiddleware = (req: AuthRequest, res: Response, next: NextFunction): void => {
  if (req.userRole !== 'admin') {
    res.status(403).json({ error: 'Admin access required' });
    return;
  }
  next();
};

// Password hashing helper
export const hashPassword = async (password: string): Promise<string> => {
  const saltRounds = 10;
  return bcrypt.hash(password, saltRounds);
};

export const comparePassword = async (password: string, hash: string): Promise<boolean> => {
  return bcrypt.compare(password, hash);
};

export const generateToken = (userId: number, role: string): string => {
  return jwt.sign({ userId, role }, JWT_SECRET, { expiresIn: '7d' });
};

// Initialize database tables
export const initDatabase = async (): Promise<void> => {
  const client = await pool.connect();

  try {
    // Create users table
    await client.query(`
      CREATE TABLE IF NOT EXISTS users (
        id SERIAL PRIMARY KEY,
        email VARCHAR(255) UNIQUE NOT NULL,
        password VARCHAR(255) NOT NULL,
        name VARCHAR(255) NOT NULL,
        role VARCHAR(50) DEFAULT 'customer',
        "createdAt" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
      )
    `);

    // Create products table
    await client.query(`
      CREATE TABLE IF NOT EXISTS products (
        id SERIAL PRIMARY KEY,
        name VARCHAR(255) NOT NULL,
        description TEXT,
        price DECIMAL(10, 2) NOT NULL,
        stock INTEGER DEFAULT 0,
        image VARCHAR(500),
        category VARCHAR(100),
        "createdAt" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
      )
    `);

    // Create orders table
    await client.query(`
      CREATE TABLE IF NOT EXISTS orders (
        id SERIAL PRIMARY KEY,
        "userId" INTEGER REFERENCES users(id) ON DELETE CASCADE,
        total DECIMAL(10, 2) NOT NULL,
        status VARCHAR(50) DEFAULT 'pending',
        "createdAt" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
      )
    `);

    // Create order_items table
    await client.query(`
      CREATE TABLE IF NOT EXISTS order_items (
        id SERIAL PRIMARY KEY,
        "orderId" INTEGER REFERENCES orders(id) ON DELETE CASCADE,
        "productId" INTEGER REFERENCES products(id) ON DELETE CASCADE,
        quantity INTEGER NOT NULL,
        price DECIMAL(10, 2) NOT NULL
      )
    `);

    // Create cart_items table
    await client.query(`
      CREATE TABLE IF NOT EXISTS cart_items (
        id SERIAL PRIMARY KEY,
        "userId" INTEGER REFERENCES users(id) ON DELETE CASCADE,
        "productId" INTEGER REFERENCES products(id) ON DELETE CASCADE,
        quantity INTEGER NOT NULL DEFAULT 1,
        UNIQUE("userId", "productId")
      )
    `);

    // Seed initial admin user if not exists
    const adminExists = await client.query(
      'SELECT id FROM users WHERE email = $1',
      ['admin@example.com']
    );

    if (adminExists.rows.length === 0) {
      const hashedPassword = await hashPassword('admin123');
      await client.query(
        'INSERT INTO users (email, password, name, role) VALUES ($1, $2, $3, $4)',
        ['admin@example.com', hashedPassword, 'Admin', 'admin']
      );
    }

    // Seed initial products if table is empty
    const productCount = await client.query('SELECT COUNT(*) FROM products');
    if (parseInt(productCount.rows[0].count) === 0) {
      const sampleProducts = [
        { name: 'Laptop Pro', description: 'High-performance laptop for professionals', price: 1299.99, stock: 50, image: 'https://via.placeholder.com/300?text=Laptop', category: 'Electronics' },
        { name: 'Wireless Mouse', description: 'Ergonomic wireless mouse with precision tracking', price: 49.99, stock: 200, image: 'https://via.placeholder.com/300?text=Mouse', category: 'Electronics' },
        { name: 'Mechanical Keyboard', description: 'RGB mechanical keyboard with Cherry MX switches', price: 149.99, stock: 100, image: 'https://via.placeholder.com/300?text=Keyboard', category: 'Electronics' },
        { name: 'USB-C Hub', description: '7-in-1 USB-C hub with HDMI and SD card reader', price: 79.99, stock: 150, image: 'https://via.placeholder.com/300?text=Hub', category: 'Electronics' },
        { name: 'Webcam HD', description: '1080p webcam with built-in microphone', price: 89.99, stock: 75, image: 'https://via.placeholder.com/300?text=Webcam', category: 'Electronics' },
        { name: 'Monitor 27"', description: '27-inch 4K IPS monitor with HDR support', price: 399.99, stock: 30, image: 'https://via.placeholder.com/300?text=Monitor', category: 'Electronics' },
        { name: 'Desk Lamp', description: 'LED desk lamp with adjustable brightness', price: 34.99, stock: 120, image: 'https://via.placeholder.com/300?text=Lamp', category: 'Home' },
        { name: 'Notebook Set', description: 'Set of 3 premium lined notebooks', price: 19.99, stock: 300, image: 'https://via.placeholder.com/300?text=Notebooks', category: 'Stationery' },
        { name: 'Desk Organizer', description: 'Bamboo desk organizer with multiple compartments', price: 29.99, stock: 80, image: 'https://via.placeholder.com/300?text=Organizer', category: 'Home' },
        { name: 'Coffee Mug', description: 'Ceramic coffee mug with ergonomic handle', price: 14.99, stock: 250, image: 'https://via.placeholder.com/300?text=Mug', category: 'Kitchen' }
      ];

      for (const product of sampleProducts) {
        await client.query(
          'INSERT INTO products (name, description, price, stock, image, category) VALUES ($1, $2, $3, $4, $5, $6)',
          [product.name, product.description, product.price, product.stock, product.image, product.category]
        );
      }
    }

    console.log('Database initialized successfully');
  } catch (error) {
    console.error('Database initialization error:', error);
    throw error;
  } finally {
    client.release();
  }
};

// Health check endpoint
app.get('/api/health', (_req: Request, res: Response) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Register routes
app.use('/api/users', usersRouter);
app.use('/api/products', productsRouter);
app.use('/api/orders', ordersRouter);

// Error handling middleware
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Server error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

// 404 handler
app.use((_req: Request, res: Response) => {
  res.status(404).json({ error: 'Not found' });
});

// Start server
const startServer = async (): Promise<void> => {
  try {
    await initDatabase();
    app.listen(PORT, () => {
      console.log(`Server running on http://localhost:${PORT}`);
      console.log(`API Base URL: http://localhost:${PORT}/api`);
    });
  } catch (error) {
    console.error('Failed to start server:', error);
    process.exit(1);
  }
};

startServer();

export { JWT_SECRET };
