  color: var(--text-secondary);
}

.product-detail-stock-icon {
  width: 20px;
  height: 20px;
}

.product-detail-stock.in-stock {
  color: var(--color-success);
}

.product-detail-stock.low-stock {
  color: var(--color-warning);
}

.product-detail-stock.out-of-stock {
  color: var(--color-error);
}

.product-detail-quantity {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.product-detail-quantity-label {
  font-size: var(--font-size-base);
  font-weight: 500;
  color: var(--text-primary);
}

.product-detail-quantity-controls {
  display: flex;
  align-items: center;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  overflow: hidden;
}

.product-detail-quantity-controls button {
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: var(--bg-tertiary);
  font-size: var(--font-size-lg);
  transition: background-color var(--transition-base);
}

.product-detail-quantity-controls button:hover:not(:disabled) {
  background-color: var(--border-color);
}

.product-detail-quantity-controls span {
  min-width: 60px;
  text-align: center;
  font-size: var(--font-size-lg);
  font-weight: 600;
}

.product-detail-actions {
  display: flex;
  gap: var(--spacing-md);
  margin-top: auto;
}

/* ==================== Checkout ==================== */
.checkout {
  display: grid;
  grid-template-columns: 2fr 1fr;
  gap: var(--spacing-xl);
}

.checkout-section {
  background-color: var(--bg-primary);
  border-radius: var(--radius-lg);
  padding: var(--spacing-xl);
  box-shadow: var(--shadow-sm);
}

.checkout-section-title {
  font-size: var(--font-size-xl);
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-lg);
  padding-bottom: var(--spacing-md);
  border-bottom: 1px solid var(--border-color);
}

.checkout-summary {
  position: sticky;
  top: calc(64px + var(--spacing-xl));
}

.checkout-summary-items {
  margin-bottom: var(--spacing-lg);
}

.checkout-summary-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
  padding: var(--spacing-sm) 0;
}

.checkout-summary-item-image {
  width: 48px;
  height: 48px;
  border-radius: var(--radius-sm);
  overflow: hidden;
  background-color: var(--bg-tertiary);
}

.checkout-summary-item-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.checkout-summary-item-info {
  flex: 1;
}

.checkout-summary-item-title {
  font-size: var(--font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
}

.checkout-summary-item-qty {
  font-size: var(--font-size-xs);
  color: var(--text-muted);
}

.checkout-summary-item-price {
  font-size: var(--font-size-sm);
  font-weight: 600;
  color: var(--text-primary);
}

.checkout-summary-divider {
  height: 1px;
  background-color: var(--border-color);
  margin: var(--spacing-md) 0;
}

.checkout-summary-row {
  display: flex;
  justify-content: space-between;
  padding: var(--spacing-sm) 0;
  font-size: var(--font-size-base);
  color: var(--text-secondary);
}

.checkout-summary-row.total {
  font-size: var(--font-size-xl);
  font-weight: 700;
  color: var(--text-primary);
  padding-top: var(--spacing-md);
  border-top: 2px solid var(--border-color);
}

/* ==================== Orders ==================== */
.order-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

.order-card {
  background-color: var(--bg-primary);
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: var(--shadow-sm);
}

.order-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-lg);
  background-color: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
}

.order-card-id {
  font-size: var(--font-size-base);
  font-weight: 600;
  color: var(--text-primary);
}

.order-card-date {
  font-size: var(--font-size-sm);
  color: var(--text-muted);
}

.order-card-body {
  padding: var(--spacing-lg);
}

.order-card-items {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
  margin-bottom: var(--spacing-lg);
}

.order-card-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.order-card-item-image {
  width: 60px;
  height: 60px;
  border-radius: var(--radius-md);
  overflow: hidden;
  background-color: var(--bg-tertiary);
}

.order-card-item-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.order-card-item-info {
  flex: 1;
}

.order-card-item-title {
  font-size: var(--font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
}

.order-card-item-qty {
  font-size: var(--font-size-xs);
  color: var(--text-muted);
}

.order-card-item-price {
  font-size: var(--font-size-sm);
  font-weight: 600;
  color: var(--text-primary);
}

.order-card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--spacing-md);
  border-top: 1px solid var(--border-color);
}

.order-card-total {
  font-size: var(--font-size-lg);
  font-weight: 700;
  color: var(--text-primary);
}

.order-status {
  display: inline-flex;
  align-items: center;
  padding: var(--spacing-xs) var(--spacing-md);
  font-size: var(--font-size-sm);
  font-weight: 500;
  border-radius: var(--radius-full);
}

.order-status.pending {
  background-color: #fef3c7;
  color: #92400e;
}

.order-status.processing {
  background-color: #dbeafe;
  color: #1e40af;
}

.order-status.shipped {
  background-color: #e0e7ff;
  color: #3730a3;
}

.order-status.delivered {
  background-color: #d1fae5;
  color: #065f46;
}

.order-status.cancelled {
  background-color: #fee2e2;
  color: #991b1b;
}

/* ==================== Auth Pages ==================== */
.auth-page {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: calc(100vh - 64px);
  padding: var(--spacing-xl);
}

.auth-card {
  width: 100%;
  max-width: 420px;
  background-color: var(--bg-primary);
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow-lg);
  padding: var(--spacing-2xl);
}

.auth-header {
  text-align: center;
  margin-bottom: var(--spacing-xl);
}

.auth-title {
  font-size: var(--font-size-2xl);
  font-weight: 700;
  color: var(--text-primary);
  margin-bottom: var(--spacing-sm);
}

.auth-subtitle {
  font-size: var(--font-size-base);
  color: var(--text-secondary);
}

.auth-footer {
  text-align: center;
  margin-top: var(--spacing-xl);
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
}

.auth-footer a {
  color: var(--color-primary);
  font-weight: 500;
}

.auth-footer a:hover {
  text-decoration: underline;
}

.auth-error {
  background-color: #fef2f2;
  border: 1px solid #fecaca;
  color: #991b1b;
  padding: var(--spacing-md);
  border-radius: var(--radius-md);
  margin-bottom: var(--spacing-lg);
  font-size: var(--font-size-sm);
}

.auth-divider {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
  margin: var(--spacing-lg) 0;
  color: var(--text-muted);
  font-size: var(--font-size-sm);
}

.auth-divider::before,
.auth-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background-color: var(--border-color);
}

/* ==================== Loading & Empty States ==================== */
.loading {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-3xl);
  color: var(--text-muted);
}

.loading-spinner {
  width: 40px;
  height: 40px;
  border: 3px solid var(--border-color);
  border-top-color: var(--color-primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

.loading-text {
  margin-top: var(--spacing-md);
  font-size: var(--font-size-base);
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-3xl);
  text-align: center;
}

.empty-state-icon {
  width: 80px;
  height: 80px;
  color: var(--text-muted);
  margin-bottom: var(--spacing-lg);
}

.empty-state-title {
  font-size: var(--font-size-xl);
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-sm);
}

.empty-state-description {
  font-size: var(--font-size-base);
  color: var(--text-secondary);
  margin-bottom: var(--spacing-lg);
}

/* ==================== Alerts & Notifications ==================== */
.alert {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-md);
  padding: var(--spacing-md) var(--spacing-lg);
  border-radius: var(--radius-md);
  font-size: var(--font-size-sm);
}

.alert-success {
  background-color: #ecfdf5;
  border: 1px solid #a7f3d0;
  color: #065f46;
}

.alert-error {
  background-color: #fef2f2;
  border: 1px solid #fecaca;
  color: #991b1b;
}

.alert-warning {
  background-color: #fffbeb;
  border: 1px solid #fde68a;
  color: #92400e;
}

.alert-info {
  background-color: #eff6ff;
  border: 1px solid #bfdbfe;
  color: #1e40af;
}

/* ==================== Modal ==================== */
.modal-overlay {
  position: fixed;
  inset: 0;
  background-color: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-lg);
  z-index: var(--z-modal-backdrop);
  animation: fadeIn var(--transition-base);
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.modal {
  width: 100%;
  max-width: 500px;
  background-color: var(--bg-primary);
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow-xl);
  z-index: var(--z-modal);
  animation: slideUp var(--transition-base);
}

